#include <stdio.h>
int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        char str[n + 1];
        scanf("%s", str);
        int countA = 0, countB = 0;
        for (int i = 0; i < n; i++) {
            if (str[i] == 'A') countA++;
            else countB++;
        }
        if (countA > countB) printf("A\n");
        else if (countB > countA) printf("B\n");
        else printf("AB\n");
    }
    return 0;
}

