const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
let i = 0;
let t;
readline.on('line', line => {
    if (i == 0) {
        t = parseInt(line);
        i++;
    } else {
        let input = line.split(' ');
        let n = parseInt(input[0]);
        let str = input[1];
        let countA = 0, countB = 0;
        for (let j = 0; j < n; j++) {
            if (str[j] == 'A') countA++;
            else countB++;
        }
        if (countA > countB) console.log('A');
        else if (countB > countA) console.log('B');
        else console.log('AB');
        i++;
        if (i > t) readline.close();
    }
});
